cat > /tmp/test_token.mjs << 'EOF'
const token = process.env.GITHUB_TOKEN || '';
const repo = process.env.GITHUB_REPO_URLS || '';
console.log('TOKEN_LEN:', token.length);
console.log('TOKEN_PREFIX:', token.slice(0, 10));
console.log('TOKEN_SUFFIX:', token.slice(-6));
console.log('REPO_URLS:', repo);

async function test() {
  if (!token) {
    console.log('GET_USER_HTTP: 000');
    console.log('ERROR: TOKEN_EMPTY');
    return;
  }
  // Test 1: GET /user
  try {
    const r1 = await fetch('https://api.github.com/user', {
      headers: { 'Authorization': `Bearer ${token}`, 'Accept': 'application/vnd.github+json', 'X-GitHub-Api-Version': '2022-11-28' }
    });
    console.log('GET_USER_HTTP:', r1.status);
    const t1 = await r1.text();
    if (r1.status === 200) {
      const j = JSON.parse(t1);
      console.log('USER_LOGIN:', j.login);
    } else {
      console.log('USER_ERROR:', t1.slice(0, 200));
    }
  } catch (e) {
    console.log('GET_USER_HTTP: 000');
    console.log('USER_ERROR:', e.message);
  }

  // Test 2: GET repo
  const repoName = 'ibb142/gh-repo-clone-ibb142-rork-global-real-estate-invest';
  try {
    const r2 = await fetch(`https://api.github.com/repos/${repoName}`, {
      headers: { 'Authorization': `Bearer ${token}`, 'Accept': 'application/vnd.github+json' }
    });
    console.log('GET_REPO_HTTP:', r2.status);
    const t2 = await r2.text();
    if (r2.status === 200) {
      const j = JSON.parse(t2);
      console.log('REPO_DEFAULT_BRANCH:', j.default_branch);
      console.log('REPO_PUSH_AT:', j.pushed_at);
    } else {
      console.log('REPO_ERROR:', t2.slice(0, 300));
    }
  } catch (e) {
    console.log('GET_REPO_HTTP: 000');
    console.log('REPO_ERROR:', e.message);
  }

  // Test 3: permissions
  try {
    const r3 = await fetch(`https://api.github.com/repos/${repoName}/collaborators/ibb142/permission`, {
      headers: { 'Authorization': `Bearer ${token}`, 'Accept': 'application/vnd.github+json' }
    });
    console.log('PERM_HTTP:', r3.status);
    const t3 = await r3.text();
    console.log('PERM:', t3.slice(0, 200));
  } catch (e) {
    console.log('PERM_HTTP: 000');
  }
}
test();
EOF
node /tmp/test_token.mjs

