{"command": "# Extract the Render API key - it's embedded in a messy string
python3 -c "
import re
with open('/home/user/rork-app/expo/.env') as f:
    for line in f:
        if line.startswith('RENDER_API_KEY='):
            raw = line.split('=', 1)[1].strip().strip('\"').strip(\"'\").strip()
            # Extract just the rnd_ key
            match = re.search(r'rnd_[a-zA-Z0-9]+', raw)
            if match:
                print(f'KEY={match.group()}')
                print(f'KEY_LEN={len(match.group())}')
            else:
                print(f'NO_MATCH raw={raw[:80]}')
            break
" 2>/dev/null"}

